import React, { useState } from 'react';
import axios from 'axios';
import './AudioUpload.css';

function AudioUpload() {
  const [audioFile, setAudioFile] = useState(null);
  const [uploadedAudioId, setUploadedAudioId] = useState('');
  const [filePath, setFilePath] = useState('');
  const [message, setMessage] = useState('');
  const [processedFiles, setProcessedFiles] = useState([]);

  const handleFileUpload = (event) => {
    const file = event.target.files[0];
    setAudioFile(file);
    setMessage('');
  };

  const uploadFile = async () => {
    if (!audioFile) {
      setMessage('Please select a file to upload.');
      return;
    }
    const formData = new FormData();
    formData.append('audio', audioFile);

    try {
      const response = await axios.post('http://localhost:5001/upload', formData);
      setUploadedAudioId(response.data.audioId);
      setFilePath(response.data.filePath);
      setMessage('File uploaded successfully!');
    } catch (error) {
      console.error('Error uploading file:', error);
      setMessage('Failed to upload file.');
    }
  };

  const applyFeature = async (feature, body) => {
    try {
      const response = await axios.post(`http://localhost:5001/${feature}`, {
        ...body,
        audioId: uploadedAudioId,
        filePath,
      });
      setMessage(response.data.message);
      setProcessedFiles((prev) => [...prev, response.data.filePath]);
    } catch (error) {
      console.error(`Error applying ${feature}:`, error);
      setMessage(`Failed to apply ${feature}.`);
    }
  };

  const handleTrim = () => {
    const start = prompt('Enter start time (in seconds):');
    const end = prompt('Enter end time (in seconds):');
    if (start && end) applyFeature('trim', { start, end });
  };

  const handleChangeSpeed = () => {
    const speed = prompt('Enter playback speed (e.g., 1.5 for 1.5x speed):');
    if (speed) applyFeature('change-speed', { speed });
  };

  const handleChangePitch = () => {
    const pitch = prompt('Enter pitch multiplier (e.g., 1.2 for higher pitch):');
    if (pitch) applyFeature('change-pitch', { pitch });
  };

  const handleFadeEffect = () => {
    const fadeInDuration = prompt('Enter fade-in duration (in seconds):');
    const fadeOutDuration = prompt('Enter fade-out duration (in seconds):');
    if (fadeInDuration && fadeOutDuration)
      applyFeature('fade', { fadeInDuration, fadeOutDuration });
  };

  const handleGenerateWaveform = () => {
    applyFeature('waveform', {});
  };

  const handleReverseAudio = () => {
    applyFeature('reverse', {});
  };

  const handleAdjustVolume = () => {
    const volume = prompt('Enter volume multiplier (e.g., 1.5 for 150%):');
    if (volume) applyFeature('adjust-volume', { volume });
  };

  return (
    <div className="audio-upload">
      <h1>Audio Customizer</h1>
      <input type="file" onChange={handleFileUpload} />
      <button onClick={uploadFile}>Upload</button>
      <div className="features">
        <button onClick={handleTrim} disabled={!filePath}>
          Trim Audio
        </button>
        <button onClick={handleChangeSpeed} disabled={!filePath}>
          Change Speed
        </button>
        <button onClick={handleChangePitch} disabled={!filePath}>
          Change Pitch
        </button>
        <button onClick={handleFadeEffect} disabled={!filePath}>
          Apply Fade
        </button>
        <button onClick={handleGenerateWaveform} disabled={!filePath}>
          Generate Waveform
        </button>
        <button onClick={handleReverseAudio} disabled={!filePath}>
          Reverse Audio
        </button>
        <button onClick={handleAdjustVolume} disabled={!filePath}>
          Adjust Volume
        </button>
      </div>
      <p>{message}</p>
      <div className="processed-files">
        <h3>Processed Files</h3>
        {processedFiles.map((file, index) => (
          <div key={index}>
            <a href={`http://localhost:5001/${file}`} target="_blank" rel="noreferrer">
              {file}
            </a>
          </div>
        ))}
      </div>
    </div>
  );
}

export default AudioUpload;
